#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline ll read()
{
	ll x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(ll x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
ll n, ans = 1;
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n = read();
	for (ll i = 2; i * i <= n; ++i)
	{
		if (n % i == 0)
		{
			ll temp = 0;
			while (n % i == 0)
			{
				n /= i;
				++temp;
			}
			if (temp % 2)
			{
				ans *= 1ll*i;
			}
		}
	}
	if (n != 1)ans *= n;
	write(ans);
	return false;
}
